//! Static instruction text constants for workflow steps.
//!
//! These are DATA — the text that agents see when they call workflow tools.
//! Separated from dispatch logic for maintainability.

pub(super) const FORMAT_RULES: &str = "\n\n**⚠️ FORMAT RULES — read carefully:**\n\n**Temporal tags** — ONLY dates/years go inside @t[...]. NEVER put names, descriptions, statuses, or any other text inside.\n- ✅ CORRECT: `@t[=2024]` `@t[~2024]` `@t[2020..2023]` `@t[2024..]` `@t[?]` `@t[=331 BCE]` `@t[=-0490]`\n- ❌ WRONG (entity names): `@t[Wolfgang Amadeus Mozart]` `@t[Mount Vesuvius]`\n- ❌ WRONG (descriptions): `@t[Complex counterpoint and fugal writing]` `@t[bright red when young]`\n- ❌ WRONG (statuses): `@t[Active Production Status: Ongoing]` `@t[No significant seismic activity]`\n- ❌ WRONG (statistics): `@t[Total Produced: 650+]` `@t[Population: 12000]`\n- ❌ WRONG (vague time words): `@t[seasonal]` `@t[since ancient times]` `@t[traditional..modern]`\n- ❌ WRONG (= in ranges): `@t[=2020..=2024]` `@t[=-300..=200]` — the `=` prefix is for SINGLE exact dates only\n- Syntax: `@t[=YYYY]` exact date, `@t[~YYYY]` approximate, `@t[YYYY..YYYY]` range, `@t[YYYY..]` ongoing, `@t[?]` unknown\n- Ranges use bare dates: `@t[2020..2024]` `@t[-300..200]` — NEVER `@t[=2020..=2024]`\n- BCE dates: `@t[=331 BCE]` or `@t[=-331]` or `@t[=-0331]` — all equivalent\n- Place the tag AFTER the fact text: `- Cap color: red to orange @t[~2024] [^1]`\n- If you don't know the date, use `@t[?]` — NEVER put text descriptions inside the brackets\n\n**Source footnotes** on every fact: `[^1]` inline, then `---\\n[^1]: Author, Title, Date` at bottom\n\nCall factbase(op='authoring_guide') for the full format reference";

// ---------------------------------------------------------------------------
// Default instruction templates for each workflow step.
// Use {placeholder} syntax for dynamic parts; resolved via config overrides.
// ---------------------------------------------------------------------------

// --- Setup workflow ---
pub(crate) const DEFAULT_SETUP_INIT_INSTRUCTION: &str = "Set up the repository directory at '{path}'.\n\n1. Create the directory if it doesn't exist\n2. Write `{path}/perspective.yaml` with the perspective configuration (next step will validate it)\n3. Optionally create a `.factbase/` directory for local config\n\nThe repository will auto-initialize when you run factbase(op='scan') in a later step.\n\nTip: If you're unsure what document types and folder structure to use for this domain, call workflow='bootstrap' with a domain description first — it will generate tailored suggestions.\n\n⚠️ NEXT: When done, you MUST call: workflow(workflow='setup', step=2)";

pub(crate) const DEFAULT_SETUP_PERSPECTIVE_INSTRUCTION: &str = "Configure the repository's perspective. Write the file `{path}/perspective.yaml` with YAML content like this:\n\n```yaml\nfocus: \"What this knowledge base is about\"\norganization: \"Who maintains it (optional)\"\nallowed_types:\n  - type1\n  - type2\n  - type3\nreview:\n  stale_days: 180\n  required_fields:\n    type1: [field1, field2]\n    type2: [field1, field2]\n```\n\nIf you ran bootstrap first, use the perspective values it suggested. Otherwise choose values appropriate for the domain.\n\n⚠️ This MUST be valid YAML written to `perspective.yaml` (not .md, not .json). The file goes in the repository root, not in .factbase/.\n\nAlso plan the folder structure — each allowed_type becomes a top-level folder. Documents are placed in type folders (e.g., `species/amanita-muscaria.md`).\n\n⚠️ NEXT: When done, you MUST call: workflow(workflow='setup', step=3)";

pub(crate) const DEFAULT_SETUP_VALIDATE_OK_INSTRUCTION: &str = "✅ perspective.yaml parsed successfully:\n  {detail}\n\nIf this looks correct, proceed to the next step.\n\n⚠️ NEXT: Call workflow(workflow='setup', step=4)";

pub(crate) const DEFAULT_SETUP_VALIDATE_ERROR_INSTRUCTION: &str = "❌ {detail}\n\n⚠️ NEXT: Fix perspective.yaml, then call workflow(workflow='setup', step=3) again to re-validate.";

pub(crate) const DEFAULT_SETUP_CREATE_INSTRUCTION: &str = "Create 2-3 example documents using factbase(op='create').\n\nIMPORTANT: First call factbase(op='authoring_guide') to learn the required document format (temporal tags, footnotes, structure).\n\nTips for first documents:\n- Place each in the appropriate type folder (e.g., 'species/amanita-muscaria.md')\n- Start with a clear # Title\n- Use exact entity names that match other document titles for automatic cross-linking\n- A definitions/ document for domain terminology is a good first document{format_rules}\n\n⚠️ NEXT: When done, you MUST call: workflow(workflow='setup', step=5)";

pub(crate) const DEFAULT_SETUP_SCAN_INSTRUCTION: &str = "Index and verify the new repository.\n\n1. Call factbase(op='scan') with time_budget_secs=120 to generate document embeddings and detect links.\n   ⚠️ PAGING: This tool is time-boxed. It WILL return `continue: true` with a `resume` token for any non-trivial repository.\n   When it does, you MUST call it again passing the resume token until `continue` is no longer in the response. Do NOT stop early.\n2. Call factbase(op='check') to run quality checks and see initial issues.\n3. Report what the scan found: how many documents were indexed, how many links were detected, and any quality issues from the check.\n\n⚠️ NEXT: When done, you MUST call: workflow(workflow='setup', step=6)";

pub(crate) const DEFAULT_SETUP_COMPLETE_INSTRUCTION: &str = "The repository is set up! Summarize what was created and suggest next steps:\n\n- **Add more content**: Use workflow='ingest' with a topic to research and add documents\n- **Fill gaps**: Use workflow='enrich' to find and fill missing information\n- **Quality check**: Use workflow='update' periodically to scan, check quality, and detect reorganization opportunities\n- **Fix issues**: Use workflow='resolve' to address any review questions\n- **Improve a document**: Use workflow='improve' with a doc_id to improve a specific document end-to-end\n\nThe knowledge base is ready for use. Any markdown editor can modify files directly — just run factbase(op='scan') afterward to re-index.";

// --- Resolve workflow ---
pub(crate) const DEFAULT_RESOLVE_QUEUE_INSTRUCTION: &str = "Process types in recommended_order (fewest questions first = quick wins). Start with: workflow resolve step=2 question_type=<first_type>. Clear each type completely before moving to the next. Skip types with 0 questions.{ctx}{deferred_note}";

pub(crate) const DEFAULT_RESOLVE_ANSWER_INTRO_INSTRUCTION: &str = "You are resolving review questions in batches. The system feeds you 15 questions at a time. You will receive multiple batches. Answer each batch and call step 2 again. The system will tell you when all questions are resolved.\n\n⚠️ EVIDENCE REQUIREMENT: Every answer MUST cite an external source (URL, document ID, book, API result, or other verifiable reference). 'Well-known historical fact', 'still accurate', or 'training data' are NOT acceptable evidence. If you cannot find an external source confirming the claim, DEFER — that is the correct action.\n\nCONFIDENCE LEVELS:\n- **verified**: You consulted an external source and found confirmation. Include the source reference (URL, document ID, API response, etc.). Use confidence='verified' (or omit — it's the default). These answers WILL be applied.\n- **believed**: You are confident from training data but did NOT find external confirmation. Use confidence='believed'. These answers stay in the queue for human review and are NOT applied.\n- **defer**: You researched and could not confirm. Prefix with 'defer:' and explain what you tried. A good defer with reasoning is better than a confident guess without evidence. Deferring means you did your job — you researched and couldn't confirm.\n\nANSWER FORMAT BY TYPE:\n\nTEMPORAL — fact line has no @t[...] tag.\n→ MUST include the tag: \"@t[YYYY] per [source] ([reference]); verified YYYY-MM-DD\"\n→ Ranges: @t[YYYY..YYYY], ongoing: @t[YYYY..], BCE: @t[-480] or @t[=480 BCE] (single dates only)\n→ IMPORTANT: = is for SINGLE exact dates only. Ranges use bare dates: @t[2020..2024], NOT @t[=2020..=2024]\n→ Unknown date: @t[?] (only when truly unfindable)\n→ WRONG: \"well-known\", \"static\", \"doesn't change\" — rejected, no audit trail\n\nMISSING — fact has no source citation.\n→ \"Source: [name] ([reference]), [date]\"\n\nSTALE — source older than {stale} days.\n→ Research \"{entity} {fact} {current year}\"\n→ Still true: \"Still accurate per [source] ([reference]), verified [date]\"\n→ Changed: \"Updated: [new info] per [source] ([reference])\"\n\nCONFLICT — two facts disagree. Read the [pattern:...] tag.\n→ Both valid (parallel, different entities): \"Not a conflict: [reason]\"\n→ One supersedes: \"Transition: adjust end date to [date] per [source]\"\n→ One wrong: \"[correct fact] per [source], remove [wrong fact]\"\n→ Cross-doc: call factbase(op='get_entity') on referenced doc for context\n\nAMBIGUOUS → clarify or create definitions/ file\nDUPLICATE → \"Duplicate of [doc_id], remove from here\"\nPRECISION → replace vague term with specific value: \"heavy losses\" → \"~500 casualties\" per [source]\nWEAK-SOURCE → use your tools to find the actual source. Update the footnote with a specific reference (URL, path, page, ISBN, RFC, channel/thread+date). If you cannot find it, change to '[^N]: UNVERIFIED — original claim: <text>'. Do not invent specific-looking citations.\n\nEXAMPLES:\n\n✅ GOOD verified answer: \"@t[2019..2023] per Wikipedia (https://en.wikipedia.org/wiki/Example); verified 2026-02-28\"\n✅ GOOD verified answer: \"@t[=2024-03] per internal doc fb:3a2c1e; verified 2026-02-28\"\n✅ GOOD defer: \"defer: Researched 'entity role 2026' using available tools — no results confirming current status\"\n❌ BAD answer: \"Still accurate, well-documented historical fact\" (no source, no evidence)\n❌ BAD answer: \"This is common knowledge\" (not verifiable)\n\nCan't find a source? → defer: researched [what], found [nothing/insufficient]. This is the RIGHT answer when evidence is lacking.\n\n⚠️ ERROR HANDLING: If you get an IO/body error from factbase(op='answer'), your response was too large. Reduce the number of answers per call (split into smaller groups) and retry.{ctx}";

pub(crate) const DEFAULT_RESOLVE_ANSWER_INSTRUCTION: &str = "Your goal is to ANSWER questions, not analyze them. Answer from knowledge first. Only research if you genuinely cannot answer. Every tool call that is not factbase(op='answer') is reducing your throughput. Minimize research calls.\n\nAnswer the questions in this batch. For each question: call factbase(op='answer') with doc_id, question_index, answer, and confidence.\n- Found a source? → confidence='verified' (or omit), include the source reference\n- Confident but no source found? → confidence='believed' (stays in queue for human review)\n- Researched and found nothing? → 'defer: researched [what], found [nothing]' — this is the correct action\n\nDo not spend context on statistics, breakdowns, or pattern analysis — spend it on factbase(op='answer') calls.\n\n⚠️ SCOPE: The resolve workflow is ONLY for answering existing questions. Do NOT call factbase(op='scan') or factbase(op='check') — those belong to the update workflow. Stay focused on the current batch.\n\n⚠️ CONTINUATION: After answering this batch, call workflow(workflow='resolve', step=2) to get the next batch. The workflow returns continue=true when more batches remain. DO NOT STOP between batches to summarize or report progress — that wastes context. Just call step=2 immediately.\n\nDO NOT STOP after answering a batch. Call workflow(workflow='resolve', step=2) immediately. Answered questions are tracked in the DB and won't reappear — your progress is safe. Only stop if your runtime forces you to (actual context limit error, timeout). If you must stop, commit your work (git add/commit) so the next session continues where you left off.{ctx}";

pub(crate) const DEFAULT_RESOLVE_APPLY_INSTRUCTION: &str = "Apply your answers by rewriting the documents directly.\n\nFor each document you answered questions about:\n1. Call factbase(op='get_entity') to read the current content\n2. Apply your answers: insert @t[...] tags, add source footnotes, resolve conflicts, etc.\n3. Call factbase(op='update') with the modified content\n\nThis gives you full control over the edits — no LLM intermediary.";

pub(crate) const DEFAULT_RESOLVE_VERIFY_INSTRUCTION: &str = "Verify your work. For each document you modified, call factbase(op='check') with doc_id and dry_run=true to check if your answers introduced new issues. If new questions appear, resolve them now.";

pub(crate) const DEFAULT_RESOLVE_CLEANUP_INSTRUCTION: &str = "Clean up the knowledge base after applying changes. Run factbase(op='scan') to re-index all documents. This prunes answered [x] questions and re-indexes modified files. Do NOT run check — resolve only cleans up, it does not generate new work.";

// --- Ingest workflow ---
pub(crate) const DEFAULT_INGEST_SEARCH_INSTRUCTION: &str = "Search factbase to see what already exists about '{topic}'. Call search(query='...') with a relevant query. Also try factbase(op='list') to browse by type.{ctx}";

pub(crate) const DEFAULT_INGEST_RESEARCH_INSTRUCTION: &str = "Research '{topic}' using your available tools. Strategies:\n- **Search**: Use available research tools for recent, authoritative information. Try specific queries like '{entity name} {fact type} {year}' rather than broad searches.\n- **Multiple sources**: Cross-reference findings across at least 2 sources before adding facts.\n- **Gather specifics**: Collect dates, numbers, names, and citations — not just summaries.\n- **Note your sources**: Track the reference (URL, document ID, publication, etc.), author, and date for every fact you find — you'll need these for footnotes.\n\nOrganize what you find by entity and section before proceeding to document creation.{ctx}";

pub(crate) const DEFAULT_INGEST_CREATE_INSTRUCTION: &str = "Create or update factbase documents with your findings. Use factbase(op='bulk_create') for multiple new entities (up to 100 at a time), create_document for a single entity, or update_document for existing ones.\n\nDocument rules:\n- Place in typed folders: people/, companies/, projects/, definitions/, etc.\n- First # Heading = document title\n- Use exact entity names matching other document titles for cross-linking\n- For acronyms or domain terms, create/update a definitions/ file\n- Never use 'Author knowledge' as a source — that's reserved for human-authored author-knowledge/ files\n- Never modify <!-- factbase:XXXXXX --> headers\n- If existing files are in the wrong folder or poorly named, feel free to rename/move them — just run factbase(op='scan') afterward\n- Entity discovery: while researching, if you discover an entity that fits the KB's allowed types (check the perspective) and is mentioned across multiple existing documents or is significant enough to warrant its own entry, create a new document for it\n- For entities external to your domain (well-known products, standards, organizations you reference but don't track in depth), add `<!-- factbase:reference -->` after the factbase ID header. These are available for linking but won't be quality-checked.\n\n⚠️ SOURCE REQUIREMENT: Every fact must have a footnote with a specific, independently verifiable source. Before writing a fact, verify it with one of your available tools and cite the specific result.\n- If you found it via web search: cite the URL\n- If you found it in a file: cite the file path\n- If you found it in email/Slack: cite the channel, thread, date, and participants\n- If you cannot verify a fact with your tools: do NOT add it. Unverified claims degrade the knowledge base.\n- NEVER cite vague sources like 'AWS documentation', 'internal docs', 'Wikipedia' (without article URL), or 'author knowledge' without specifics.\n- GOOD citations: URL, file path, book+page, email with subject+date, Slack channel+thread+date, RFC number, ISBN\n- BAD citations: 'AWS documentation', 'internal docs', 'author knowledge', 'Wikipedia' without article name/URL\n\nKeep track of all document IDs you create — you'll need them for the verify step.{fields}{format_rules}\n\n⚠️ NEXT: When done creating documents, you MUST call: workflow(workflow='ingest', step=4)";

pub(crate) const DEFAULT_INGEST_VERIFY_INSTRUCTION: &str = "Verify the quality of your new documents.\n\n1. Call factbase(op='check') with doc_ids=[list of all document IDs you created] to run quality checks on them.\n2. Review the results — questions indicate quality issues:\n   - Missing @t[] tags: add temporal context (when was this verified? what year?)\n   - Missing sources: add footnotes for any unsourced claims\n   - Ambiguous terms: clarify or create definitions/ entries\n3. Fix what you can NOW using factbase(op='update'). The rest stays in the review queue for resolve.\n4. Run factbase(op='scan') to re-index after any fixes.\n\nAlso note any frequently-mentioned names that don't have their own documents — these are candidates for new entities.\n\n⚠️ NEXT: When done verifying, you MUST call: workflow(workflow='ingest', step=5)";

pub(crate) const DEFAULT_INGEST_LINKS_INSTRUCTION: &str = "Discover cross-references for your new documents.\n\n1. Call factbase(op='links') with exclude_types matching the new document types (cross-type discovery, min_similarity=0.5).\n2. Review suggestions: does the candidate genuinely relate to the source?\n3. For confirmed links, call factbase(op='links', action='store') with the source_id and target_id pairs. factbase(op='links', action='store') writes References: to source files AND Referenced by: to target files automatically.\n4. Bidirectional discovery: for each existing document your new docs link TO, check if that existing document's content mentions any of your new document titles. If so, store the reverse link too (existing → new) via store_links.\n5. Record: links_added, documents_modified";

// --- Enrich workflow ---
pub(crate) const DEFAULT_ENRICH_REVIEW_INSTRUCTION: &str = "Review the entity_quality list (sorted by attention_score, highest first). Reference entities are excluded — they exist for linking, not enrichment.\nPick the top 3-5 entities that need work. You will enrich them ONE AT A TIME — fully completing each before moving to the next.\n\nCall factbase(op='get_entity') on the first entity to begin.{ctx}";

pub(crate) const DEFAULT_ENRICH_GAPS_INSTRUCTION: &str = "Score this document before researching:\n\n1. Temporal: X of Y fact lines have @t tags = Z%\n2. Sources: X of Y fact lines have [^N] citations = Z%\n3. Missing fields: [list any required by perspective]{fields}\n4. Review questions: X unanswered\n5. Gaps: list ALL areas where you could add substantive facts — sections that are thin, topics mentioned but not developed, missing context or history\n\nResearch the LOWEST coverage area first, then continue through all gaps.";

pub(crate) const DEFAULT_ENRICH_RESEARCH_INSTRUCTION: &str = "Research and update THIS document. Work through ALL gaps you identified — don't stop at 3-5.\n\nFor each gap:\n1. Search specifically: \"{entity name} {fact}\" — targeted beats broad\n2. Read the full page, not just snippets\n3. Every new fact MUST have BOTH @t[YYYY] AND [^N] citation — no exceptions\n4. Mention related KB entities by exact title in prose (enables link detection)\n\n⚠️ SOURCE REQUIREMENT: Every footnote must be specific enough that someone else could independently find the same source.\n- Before writing a fact, verify it with one of your available tools and cite the specific result (URL, file path, etc.)\n- If you cannot verify a fact with your tools: do NOT add it.\n- When enriching, check existing citations. If a citation is vague (e.g. 'AWS documentation' without a URL, 'Wikipedia' without article name), look up the actual source with your tools and update the footnote with the specific URL or reference.\n- GOOD: URL, file path, book+page, email with subject+date, Slack channel+thread+date, RFC number, ISBN\n- BAD: 'AWS documentation', 'internal docs', 'author knowledge', 'Wikipedia' without article name/URL\n\nKeep going until you've exhausted your research for this document. More well-sourced facts = better.\n\nCall factbase(op='update') with the enriched content. Then verify: call factbase(op='check') with doc_id and dry_run=true.\n\nRecord: facts added, sources added, @t tags added, issues from verify.\n\n⚠️ REPEAT for the next document:\n1. Call factbase(op='get_entity') on the next entity from your list\n2. Score it (same as step 2)\n3. Research + update + verify (same as this step)\nContinue until all documents are done.\n\nRules:\n- Preserve ALL existing content — add, don't replace\n- Resolve review questions when your research provides answers\n- Create documents for significant missing entities{ctx}{format_rules}";

pub(crate) const DEFAULT_ENRICH_VERIFY_INSTRUCTION: &str = "Report totals across all documents enriched:\n\n| Document | +Facts | +Sources | +@t | Issues |\n|----------|--------|----------|-----|--------|\n| ... | ... | ... | ... | ... |\n\nTotals: X facts, X sources, X @t tags added. X questions resolved. X new issues.\nAssessment: biggest improvement, remaining gaps, recommended next step.";

// --- Improve workflow ---
pub(crate) const DEFAULT_IMPROVE_CLEANUP_INSTRUCTION: &str = "Read the document and fix any issues{doc_hint}. Call factbase(op='get_entity') with the doc_id to read its full content.\n\nCheck for and fix:\n- Corruption artifacts (malformed review queue sections, broken markdown)\n- Duplicate entries (same fact stated multiple times)\n- Formatting inconsistencies (inconsistent heading levels, missing blank lines)\n- Orphaned footnote references or definitions\n\nIf issues are found, call factbase(op='update') to fix them. If the document looks clean, move to the next step.{ctx}";

pub(crate) const DEFAULT_IMPROVE_RESOLVE_INSTRUCTION: &str = "Resolve outstanding review questions{doc_hint}. Call factbase(op='review_queue') with doc_id to see pending questions.\n\nFor each unanswered question:\n- stale: Source is older than {stale} days. Search for current info\n- missing: Find a source citation\n- conflict: Check the [pattern:...] tag — parallel_overlap, same_entity_transition, date_imprecision are often not real conflicts\n- temporal: The fact line is MISSING an @t[...] temporal tag — that is what this question means. Your answer MUST include the @t[...] tag to add, plus a source. Answer: '@t[YYYY] per [source] ([URL]); verified [YYYY-MM-DD]' or '@t[YYYY..YYYY] per [source]' for ranges. The = prefix is for SINGLE exact dates only (e.g. @t[=2024-03]) — NEVER use = in ranges. Just citing a source in prose does NOT resolve it — the @t[...] tag must appear in your answer. Use @t[?] only when no date is findable. Every datable fact gets a tag regardless of domain or era. Never answer with bare dismissals like 'static fact', 'well-known', or 'historical constant' — these provide no audit trail\n- ambiguous: Clarify the term or create a definitions document\n- precision: Replace vague qualifier with a specific value or measurement, e.g. 'heavy losses' → '~500 casualties'\n- duplicate: Identify the canonical entry\n\nCall factbase(op='answer') with your answers. If you can't resolve a question, defer it with a note about what you tried.\n\nAfter answering, apply your changes directly: call factbase(op='get_entity') to read the document, apply the edits (insert @t tags, add footnotes, etc.), then call factbase(op='update') with the modified content.{ctx}";

pub(crate) const DEFAULT_IMPROVE_ENRICH_INSTRUCTION: &str = "Enrich the document with new information{doc_hint}. Call factbase(op='get_entity') to read the current content (it may have changed from earlier steps).\n\nIdentify gaps:\n- Dynamic facts missing temporal tags\n- Facts without source citations\n- Sparse sections that could be expanded\n- Missing standard fields for the document type\n- Weak identification: if the title is an alias, abbreviation, or partial label and a fuller canonical name exists, update the title\n- Poor file organization: if the file is in the wrong folder or has an unclear name, rename/move it with file tools{fields}\n\nResearch the gaps using your available tools:\n- Use available research tools for current data on each gap — use specific queries per entity/fact\n- Read full pages when snippets look relevant\n- Cross-reference important facts across multiple sources\n\nThen call factbase(op='update') to add findings.\n\nRules:\n- Preserve all existing content — add to it, don't replace\n- Always add temporal tags and source footnotes on new facts\n- Don't add speculative information — only add what you can source\n- Use @t[?] for facts you found but can't date precisely\n- If you rename or move any files, run factbase(op='scan') afterward to re-index{ctx}";

pub(crate) const DEFAULT_IMPROVE_CHECK_INSTRUCTION: &str = "Verify the document quality{doc_hint}. Call factbase(op='check') with doc_id and dry_run=true to check for any remaining or newly introduced issues.\n\nReport what you find:\n- How many questions remain vs. how many were resolved\n- Any new issues introduced during enrichment\n- Overall document health assessment{compare_note}";

/// Default template for the bootstrap prompt.
pub(crate) const DEFAULT_BOOTSTRAP_PROMPT: &str = r##"Design a knowledge base structure for: "{domain}"{entity_types}

Return a JSON object with exactly these 4 fields:

1. "document_types": array of {"name": "lowercase-hyphenated", "description": "one line"}
   — 3-5 types that reflect how practitioners organize knowledge in this domain.

2. "folder_structure": array of folder paths (e.g. ["airlines/", "airports/", "definitions/"])

3. "templates": object mapping each type name to a markdown template. Each template:
   - Starts with # placeholder title
   - Has 2-3 section headings suited to the type
   - Shows example bullets with @t[YYYY] or @t[YYYY..YYYY] temporal tags on time-sensitive facts
   - CRITICAL: @t[...] tags contain ONLY dates — NEVER names, descriptions, or non-date content
     ✅ @t[=2024], @t[~2024-03], @t[2020..2023], @t[2024..], @t[?], @t[=331 BCE]
     ❌ @t[Wolfgang Amadeus Mozart], @t[Complex counterpoint], @t[Active Production Status: Ongoing]
     ❌ @t[=2020..=2024] — the = prefix is for single exact dates only, never in ranges
   - Includes [^1] footnote references and a --- section with source definitions
   - Is realistic for the domain

4. "perspective": {"focus": "one-line mission", "allowed_types": ["your type names"]}

Return ONLY valid JSON, no markdown fences or explanation."##;

// --- Create workflow ---
pub(crate) const DEFAULT_CREATE_COMPLETE_INSTRUCTION: &str = "The knowledge base is set up! Summarize what was created and suggest next steps:\n\n- **Add content**: Use workflow='add' with topic='X' to research and add new entities\n- **Fill gaps**: Use workflow='add' (no topic) to find and fill missing information\n- **Quality check**: Use workflow='maintain' to scan, check quality, and resolve issues\n- **Research refresh**: Use workflow='refresh' to update entities with latest information from external sources\n- **Improve a document**: Use workflow='add' with doc_id='X' to improve a specific document\n\nThe knowledge base is ready for use. Any markdown editor can modify files directly — just run factbase(op='scan') afterward to re-index.";

// --- Maintain workflow ---
pub(super) const DEFAULT_MAINTAIN_SCAN_INSTRUCTION: &str = "Re-index the factbase to pick up file changes.\n\n1. Call factbase(op='scan') with time_budget_secs=120.\n   ⚠️ PAGING: This tool is time-boxed. It WILL return `continue: true` with a `resume` token for any non-trivial repository.\n   When it does, you MUST call it again passing the resume token until `continue` is no longer in the response.\n   This may take many iterations — that is normal. Do NOT stop early, skip ahead, or report partial results.\n2. Record: documents_total, temporal_coverage_pct, source_coverage_pct{ctx}";

pub(super) const DEFAULT_MAINTAIN_DETECT_LINKS_INSTRUCTION: &str = "Detect cross-document links via title string matching.\n\n1. Call factbase(op='detect_links') with time_budget_secs=120.\n   ⚠️ PAGING: This tool is time-boxed. It WILL return `continue: true` with a `resume` token for large repositories.\n   When it does, you MUST call it again passing the resume token until `continue` is no longer in the response.\n2. Record: links_detected, docs_processed{ctx}";

pub(super) const DEFAULT_MAINTAIN_CHECK_INSTRUCTION: &str = "Run quality checks to find stale facts, missing sources, temporal gaps, and other issues.\n\n1. Call factbase(op='check') (one call — no paging needed).\n2. Record: questions_total, breakdown by type (stale, conflict, temporal, missing)\n   - Mostly stale → KB is aging, needs fresh sources\n   - Mostly temporal → facts lack dates, timeline is murky\n   - Mostly missing → claims lack evidence\n\n⚠️ TEMPORAL QUESTION FILTERING: After check completes, review the generated temporal questions. Some will have confidence='low' with a reason. Dismiss low-confidence temporal questions about:\n- Stable feature descriptions or capability lists\n- Glossary definitions or reference material\n- Facts sourced from official documentation pages that describe current capabilities\nOnly keep temporal questions about claims that could genuinely become outdated. Dismiss the rest via factbase(op='answer') with answer='dismiss: [reason]'.";

pub(super) const DEFAULT_MAINTAIN_RESOLVE_INSTRUCTION: &str = "Resolve all review questions. Run the full resolve workflow now:\n\n1. Call workflow(workflow='resolve', step=1) to see the queue distribution\n2. Call workflow(workflow='resolve', step=2) to get the first batch of questions\n3. Answer the batch, then call workflow(workflow='resolve', step=2) again\n\nLOOP: Resolve step 2 returns `continue: true` with a `completion_gate` showing progress (e.g. '450/3551 resolved'). You MUST keep calling step=2 until `continue` is false. You do not decide when to stop — not context size, not your judgment, not batch count. Your runtime compacts automatically. This may take hundreds of iterations for large KBs.\n\n4. When step 2 returns `continue: false`, call workflow(workflow='resolve', step=3) to apply answers\n5. Follow steps 4-6 (verify, cleanup) until resolve reports complete=true\n6. Then call workflow(workflow='maintain', step=7) to continue maintenance\n\n⚠️ ERROR HANDLING: If you get IO/body errors from factbase(op='answer'), your response was too large. Split into smaller batches and retry.{ctx}";

pub(super) const DEFAULT_MAINTAIN_LINKS_INSTRUCTION: &str = "Review link suggestions to improve cross-document connectivity.\n\n1. Call factbase(op='links') TWICE for better coverage:\n   a. Cross-type discovery: use exclude_types matching the most common doc type with min_similarity=0.5.\n   b. Same-type discovery: use include_types matching a specific type with min_similarity=0.7.\n2. Review each suggestion: does the candidate document genuinely relate to the source?\n3. For confirmed links, call factbase(op='links', action='store') with the source_id and target_id pairs.\n4. Record: links_added, documents_modified";

pub(super) const DEFAULT_MAINTAIN_ORGANIZE_INSTRUCTION: &str = "Analyze the knowledge base structure and execute improvements.\n\n1. Call factbase(op='organize', action='analyze') to detect reorganization opportunities.\n2. Review candidates: merge, split, misplaced, duplicates, ghost files.\n3. Execute changes using the organize operations listed below.\n4. Call factbase(op='organize', action='execute_suggestions') to process any pending move/rename/title suggestions from prior updates.\n\nYou have these organize operations available via factbase(op='organize'):\n- action='analyze' — detect merge candidates, duplicates, misplaced files, split candidates\n- action='move' — relocate a file to a different directory (cascades all wikilink updates)\n- action='merge' — combine two documents into one (appends source body to target, redirects links, deletes source). Params: source_id, target_id\n- action='split' — break one multi-topic document into separate documents. Params: doc_id, sections (array of {title, content})\n- action='delete' — clean delete with DB cleanup and link cascade. Params: doc_id\n- action='retype' — change document type without moving\n- action='execute_suggestions' — process pending move/rename/title suggestions from prior updates\n- action='apply' — process answered orphan markers\n\n⚠️ IMPORTANT: Do NOT use shell commands (rm, mv, cp) to manipulate KB files. Always use factbase organize operations — they handle DB cleanup, link cascades, and wikilink updates that shell commands miss.";

pub(super) const DEFAULT_MAINTAIN_REPORT_INSTRUCTION: &str = "Write a final maintenance report.\n\n## Maintenance Summary\n- Documents scanned: X\n- Links detected: X\n- Link suggestions applied: X\n- Organize candidates: X (merge/split/misplaced/duplicates)\n- Questions found: X\n- Questions resolved: X\n- Questions deferred: X (need human attention)\n- Remaining questions: X\n\n## Health Assessment\nOne paragraph: overall KB health after maintenance, what was fixed, and any remaining issues that need human attention.\n\nIf deferred items exist, remind the user to review them with factbase(op='deferred').";

// --- Refresh workflow ---
pub(super) const DEFAULT_REFRESH_SCAN_INSTRUCTION: &str = "Re-index the factbase to pick up file changes.\n\n1. Call factbase(op='scan') with time_budget_secs=120.\n   ⚠️ PAGING: This tool is time-boxed. It WILL return `continue: true` with a `resume` token for any non-trivial repository.\n   When it does, you MUST call it again passing the resume token until `continue` is no longer in the response.\n2. Record: documents_total, temporal_coverage_pct, source_coverage_pct{ctx}";

pub(super) const DEFAULT_REFRESH_CHECK_INSTRUCTION: &str = "Run quality checks to identify stale facts and other issues.\n\n1. Call factbase(op='check') (one call — no paging needed).\n2. Record: questions_total, breakdown by type\n3. Pay special attention to stale questions — these are the primary targets for refresh";

pub(super) const DEFAULT_REFRESH_RESEARCH_INSTRUCTION: &str = "Research and update entities with latest information.\n\nFor each entity that needs refreshing (prioritize stale facts, then low temporal/source coverage):\n\n1. Call factbase(op='get_entity') to read the current document\n2. Use your available tools (web search, local search, etc.) to find the latest information about this entity\n3. Compare findings with existing facts:\n   - Facts that changed: update the fact text, add new @t[...] tag with current date, update source footnote\n   - Facts confirmed current: update the @t[~YYYY-MM] tag to show when last verified, update source\n   - New facts discovered: add with @t[...] tag and source footnote\n   - Entities discovered during research: create new documents if they fit the KB's allowed types\n4. Call factbase(op='update') with the modified content\n\nWork through entities systematically. After updating each entity, move to the next.\n\n⚠️ SOURCE REQUIREMENT: Every update MUST cite a specific, verifiable source. Do not update facts without evidence.{ctx}{format_rules}";

pub(super) const DEFAULT_REFRESH_RESOLVE_INSTRUCTION: &str = "Resolve any review questions generated during the refresh.\n\n1. Call workflow(workflow='resolve', step=1) to see the queue distribution\n2. Process questions using the resolve workflow (step=2 loop)\n3. Apply answers and verify\n\nSince you just researched these entities, you should be able to answer most questions from your recent findings.{ctx}";

pub(super) const DEFAULT_REFRESH_CLEANUP_INSTRUCTION: &str = "Clean up after refresh. Run factbase(op='scan') to re-index all modified documents and prune answered questions.";

pub(super) const DEFAULT_REFRESH_REPORT_INSTRUCTION: &str = "Write a refresh report.\n\n## Refresh Summary\n- Entities researched: X\n- Facts updated: X\n- Facts confirmed current: X\n- New facts added: X\n- New entities created: X\n- Questions resolved: X\n- Questions deferred: X\n\n## Changes\nList the most significant changes discovered during refresh.\n\n## Health Assessment\nOverall KB freshness after refresh, and any entities that could not be verified.";

// --- Correct workflow ---
pub(super) const DEFAULT_CORRECT_PARSE_INSTRUCTION: &str = "Parse the correction to identify what needs to be fixed across the knowledge base.\n\nCorrection: {correction}\n{source_note}\n\nYour task:\n1. Extract the key entities mentioned in the correction (names, terms, concepts)\n2. Classify the correction type:\n   - relational: changes a relationship between entities (e.g., parent/subsidiary, authored by, member of)\n   - temporal: changes when something happened or a date/period (e.g., completed in January not March)\n   - factual: changes a property or attribute (e.g., HQ location, population, chemical formula)\n   - status: changes current state of an entity (e.g., departed, discontinued, merged)\n   - identity: adds an alias, alternate name, or clarifies identity (e.g., also known as, renamed to)\n   - classification: changes category, type, or classification (e.g., toxic vs deadly, mammal vs marsupial)\n3. Identify the OLD value (what the KB currently says) and the NEW value (what is true)\n4. Extract temporal context — any dates, date ranges, or temporal markers from the correction itself (e.g., \"in January 2026\", \"as of Q3\", \"since 2024-06\"). If the correction contains no temporal information, report \"none\"\n5. Determine scope: \"single\" if this corrects one specific fact, \"systemic\" if the misconception may appear in many forms across multiple documents\n6. Generate search terms that would find documents containing or implying the false claim — include:\n   - Each entity name individually\n   - Entity names paired together\n   - Relationship terms from the false claim (e.g., parent, subsidiary, division, acquired, merged)\n   - Synonyms and alternative phrasings\n\nReport your analysis:\n- Entities: [list]\n- Correction type: [relational | temporal | factual | status | identity | classification]\n- Old value: [what the KB currently says]\n- New value: [what is true]\n- Temporal context: [dates/ranges from the correction, or \"none\"]\n- Scope: [single | systemic]\n- False claim: [description]\n- True fact: [description]\n- Search terms: [list of queries to run]\n\n⚠️ NEXT: When done, call workflow(workflow='correct', step=2)";

pub(super) const DEFAULT_CORRECT_SEARCH_INSTRUCTION: &str = "Search for all documents that may contain or imply the false claim.\n\nCorrection: {correction}\n\nFor each search term you identified in step 1:\n1. Call search(query='...') — this does semantic matching by default\n2. Also try search(query='...', mode='content') for exact text matches on key phrases\n\nCollect ALL matching documents. Deduplicate by document ID.\n\nReport:\n- Documents found: [count]\n- For each document: ID, title, and the relevant snippet that may contain the false claim\n\n⚠️ NEXT: When done, call workflow(workflow='correct', step=3)";

pub(super) const DEFAULT_CORRECT_FIX_INSTRUCTION: &str = "Fix each document that contains or implies the false claim.\n\nCorrection: {correction}\n{source_note}\n\nFor each document from step 2:\n1. Call factbase(op='get_entity') with the document ID to read its full content\n2. Evaluate whether the document actually contains or implies the false claim\n3. If YES:\n   a. Rephrase the correction IN THE CONTEXT OF THIS DOCUMENT. Do NOT copy the full correction text verbatim. Each document should read naturally as if it were written correctly from the start.\n      - A document about one entity should only mention what is relevant to THAT entity (e.g., fix a role or affiliation, don't explain an entire organizational hierarchy)\n      - A document that IS the overview/hub for the corrected topic should contain the full structural explanation\n      - A document that merely cross-references the corrected fact should get a brief, accurate update\n      Think: what would a knowledgeable author write in THIS document? Write that — not a copy-paste of the correction.\n   b. Add a temporal tag on the corrected fact. Use the date from the correction's temporal context if available:{temporal_hint}\n   c. Add a source footnote citing the correction source{source_footnote}\n   d. Call factbase(op='update') with the modified content\n4. If NO: skip — search may return false positives\n\nProcess documents one at a time. Some may need a single line changed, others may need whole sections rewritten.\n\nRecord:\n- Documents fixed: [count]\n- Documents skipped: [count]\n- For each fix: document ID, title, what was changed\n\n⚠️ NEXT: When done, call workflow(workflow='correct', step=4)";

pub(super) const DEFAULT_CORRECT_CLEANUP_INSTRUCTION: &str = "Clean up after corrections.\n\n1. Call factbase(op='organize', action='execute_suggestions') to process any pending move/rename/title suggestions.\n2. Call factbase(op='scan') to re-index all modified documents\n   ⚠️ PAGING: This tool is time-boxed. Call again with resume token until complete.\n3. Search again for the key entities from the correction to verify no remaining instances of the false claim\n4. If any remain, fix them now\n\nWrite a final report:\n\n## Correction Summary\n- Correction: {correction}\n- Source: {source}\n- Documents fixed: X\n- Documents skipped: X\n- Remaining issues: X (if any)\n\n## Changes Made\nList each document that was modified and what changed.\n\n## Verification\nConfirm the false claim no longer appears in the knowledge base, or note any documents that need manual review.";

// --- Transition workflow ---
pub(super) const DEFAULT_TRANSITION_PARSE_INSTRUCTION: &str = "Parse the transition to identify what changed and how it affects the knowledge base.\n\nChange: {change}\n{source_note}\n\nUnlike a correction (where old info was FALSE), a transition means the old info WAS TRUE and has now CHANGED. Historical references to the old value are valid for their time period.\n\nYour task:\n1. Extract the entity that changed (the subject of the transition)\n2. Classify the change type:\n   - rename: entity changed its name (old name was valid until the change date)\n   - merger: two or more entities combined into one\n   - acquisition: one entity absorbed another\n   - role_change: entity's role, position, or function changed\n   - reorganization: structural change (teams merged, divisions split, etc.)\n   - reclassification: entity changed category or type\n3. Identify the OLD value (what it was) and the NEW value (what it is now)\n4. Determine the effective date: when did this change take effect? Use the provided date, or today ({today}) if not specified\n5. Generate search terms to find all documents referencing the entity — include:\n   - The old name/value\n   - The new name/value\n   - Related entities (e.g., parent org, team members, linked entities)\n   - Abbreviations or aliases\n\nReport your analysis:\n- Entity: [what changed]\n- Change type: [rename | merger | acquisition | role_change | reorganization | reclassification]\n- Old value: [what it was]\n- New value: [what it is now]\n- Effective date: [YYYY-MM-DD]\n- Search terms: [list of queries to run]\n\n⚠️ NEXT: When done, call workflow(workflow='transition', step=2)";

pub(super) const DEFAULT_TRANSITION_NOMENCLATURE_QUESTION: &str = "Before making changes, I need to know how you want the entity referenced going forward.\n\nChange: {change}\nOld value: from step 1 analysis\nNew value: from step 1 analysis\nEffective date: from step 1 analysis\n\nHow would you like me to reference this going forward?\n\n1. **Replace with context**: Use `<new value> (formerly <old value>)` in current references\n2. **Replace clean**: Just `<new value>` — old name only in the entity's own history section\n3. **Keep old in history**: Current docs say `<new value>`, historical docs (before change date) keep `<old value>`\n4. **Custom**: You tell me the format\n\nPlease respond with your choice (1-4, or describe a custom format).";

pub(super) const DEFAULT_TRANSITION_NOMENCLATURE_CONFIRMED: &str = "Nomenclature preference confirmed: {nomenclature}\n\nNow search for all documents referencing the entity. Use both the old and new values as search terms.\n\nFor each search term from step 1:\n1. Call search(query='...') — this does semantic matching by default\n2. Also try search(query='...', mode='content') for exact text matches on the old name/value\n\nCollect ALL matching documents. Deduplicate by document ID.\n\nClassify each document:\n- **Entity overview**: the primary document about the entity that changed (gets full transition history)\n- **Current reference**: mentions the entity in a current context (gets nomenclature update)\n- **Historical reference**: mentions the entity in a past context before the change date (may keep old name)\n\nReport:\n- Documents found: [count]\n- For each: ID, title, classification (overview/current/historical), relevant snippet\n\n⚠️ NEXT: When done, call workflow(workflow='transition', step=4)";

pub(super) const DEFAULT_TRANSITION_APPLY_INSTRUCTION: &str = "Apply the transition to each document found in step 3.\n\nChange: {change}\nNomenclature: {nomenclature}\nEffective date: {effective_date}\n{source_note}\n\nFor each document:\n1. Call factbase(op='get_entity') to read the full content\n2. Apply changes based on document classification:\n\n   **Entity overview doc** (the primary doc about the entity):\n   - Add a transition entry with temporal boundaries:\n     `- <old value> @t[..{effective_date}]`\n     `- <new value> @t[{effective_date}..]`\n   - Add a source footnote for the transition{source_footnote}\n   - Update the title if it uses the old name\n   - Set suggested_rename if the filename should change\n   - Set suggested_move if the directory should change\n\n   **Current reference docs** (mention entity in current context):\n   - Apply the user's nomenclature preference\n   - Add temporal tag on the updated reference: @t[{effective_date}..]\n\n   **Historical reference docs** (mention entity before change date):\n   - If nomenclature is 'keep old in history': leave the old name, it was correct at the time\n   - Otherwise: apply the nomenclature preference\n   - Preserve any existing temporal tags — they document when the old name was valid\n\n3. Call factbase(op='update') with the modified content\n\nDo NOT change historical footnotes, archived references, or quoted material — they were correct at the time.\n\nRecord:\n- Documents updated: [count]\n- Documents skipped: [count]\n- Org suggestions: [list of suggested renames/moves]\n\n⚠️ NEXT: When done, call workflow(workflow='transition', step=5)";

pub(super) const DEFAULT_TRANSITION_ORGANIZE_INSTRUCTION: &str = "Execute any pending organizational changes from the transition.\n\n1. Call factbase(op='organize', action='execute_suggestions') to process pending move/rename/title suggestions from step 4.\n2. Record what was executed: files renamed, directories changed.\n\n⚠️ NEXT: When done, call workflow(workflow='transition', step=6)";

pub(super) const DEFAULT_TRANSITION_MAINTAIN_INSTRUCTION: &str = "Run a maintenance pass to catch ripple effects from the transition.\n\n1. Call factbase(op='scan') to re-index all modified documents.\n   ⚠️ PAGING: This tool is time-boxed. Call again with resume token until complete.\n2. Call factbase(op='check') to detect any new issues introduced by the transition.\n3. If new questions appear, resolve them now — they are likely caused by the transition changes.\n\n⚠️ NEXT: When done, call workflow(workflow='transition', step=7)";

pub(super) const DEFAULT_TRANSITION_REPORT_INSTRUCTION: &str = "Write a final transition report.\n\n## Transition Summary\n- Change: {change}\n- Effective date: {effective_date}\n- Source: {source}\n- Nomenclature: {nomenclature}\n\n## Documents Updated\nList each document that was modified and what changed.\n\n## Organizational Changes\nList any files renamed, directories changed, or titles updated.\n\n## Ripple Effects\nNote any issues found during the maintenance pass and how they were resolved.\n\n## Verification\nConfirm the transition was applied consistently across the knowledge base.";
